import React from "react";
import "./Sidebar.css";

const Sidebar = () => {
    return (
        <div className="sidebar">
            <h2 className="sidebar-title">Electronic Smart Labeling System</h2>
            <ul className="menu">
                <li>Real-Time Pricing</li>
                <li>Inventory</li>
                <li>Alerts</li>
                <li>Analytics</li>
                <li>Settings</li>
                <li>Help</li>
            </ul>
            <button className="logout-button">Logout</button>
        </div>
    );
};

export default Sidebar;
